69	pub fn make_parser_for(lang: Lang) -> tree_sitter::Parser {
70	    let mut parser = tree_sitter::Parser::new();
71	    let language: tree_sitter::Language = match lang {
72	        Lang::Rust => tree_sitter_rust::LANGUAGE.into(),
73	        Lang::JavaScript => tree_sitter_javascript::LANGUAGE.into(),
74	        Lang::TypeScript => tree_sitter_typescript::LANGUAGE_TYPESCRIPT.into(),
75	    };
76	    parser
77	        .set_language(&language)
78	        .expect("failed to load grammar");
79	    parser
80	}
