94	pub fn parse_source_tree_for(source: &str, lang: Lang) -> Result<tree_sitter::Tree, &'static str> {
95	    let tree = make_parser_for(lang)
96	        .parse(source, None)
97	        .ok_or("parse returned None")?;
98	    if tree.root_node().has_error() {
99	        return Err("parse error");
100	    }
101	    Ok(tree)
102	}
