122	pub fn extract_functions_with_config(
123	    node: tree_sitter::Node,
124	    source: &str,
125	    file: &str,
126	    config: &LangConfig,
127	    functions: &mut Vec<FunctionInfo>,
128	) {
129	    match config.lang {
130	        Lang::Rust => extract_rust_functions(node, source, file, functions),
