137	fn extract_rust_functions(
138	    node: tree_sitter::Node,
139	    source: &str,
140	    file: &str,
141	    functions: &mut Vec<FunctionInfo>,
142	) {
143	    match node.kind() {
144	        "function_item" => {
145	            functions.push(make_function_info(node, source, file, &RUST_CONFIG));
146	        }
147	        "let_declaration" => {
148	            extract_rust_let_declaration(node, source, file, functions);
149	        }
150	        _ => {
151	            for child in children_of(node) {
152	                extract_rust_functions(child, source, file, functions);
153	            }
154	        }
155	    }
156	}
