167	fn extract_rust_let_declaration(
168	    node: tree_sitter::Node,
169	    source: &str,
170	    file: &str,
171	    functions: &mut Vec<FunctionInfo>,
172	) {
173	    if let Some(val) = find_child_by_field(node, "value")
174	        && val.kind() == "closure_expression"
175	    {
176	        functions.push(make_function_info(node, source, file, &RUST_CONFIG));
177	    }
178	    for child in children_of(node) {
179	        if child.kind() != "closure_expression" {
180	            extract_rust_functions(child, source, file, functions);
181	        }
182	    }
183	}
