185	fn extract_jsts_export_statement(
186	    node: tree_sitter::Node,
187	    source: &str,
188	    file: &str,
189	    config: &LangConfig,
190	    functions: &mut Vec<FunctionInfo>,
191	) {
192	    let fn_decls: Vec<_> = children_of(node)
193	        .into_iter()
194	        .filter(|c| c.kind() == "function_declaration")
195	        .collect();
196	    if fn_decls.is_empty() {
197	        for child in children_of(node) {
198	            extract_jsts_functions(child, source, file, config, functions);
199	        }
200	    } else {
201	        for child in fn_decls {
202	            functions.push(make_function_info(child, source, file, config));
203	        }
204	    }
205	}
