235	fn try_extract_jsts_node(
236	    node: tree_sitter::Node,
237	    source: &str,
238	    file: &str,
239	    config: &LangConfig,
240	    functions: &mut Vec<FunctionInfo>,
241	) -> bool {
242	    match node.kind() {
243	        "function_declaration" => functions.push(make_function_info(node, source, file, config)),
244	        "export_statement" => extract_jsts_export_statement(node, source, file, config, functions),
245	        "lexical_declaration" => {
246	            extract_jsts_lexical_declaration(node, source, file, config, functions)
247	        }
248	        "class_body" => extract_jsts_class_body(node, source, file, config, functions),
249	        _ => return false,
250	    }
251	    true
252	}
