254	fn extract_jsts_functions(
255	    node: tree_sitter::Node,
256	    source: &str,
257	    file: &str,
258	    config: &LangConfig,
259	    functions: &mut Vec<FunctionInfo>,
260	) {
261	    if !try_extract_jsts_node(node, source, file, config, functions) {
262	        for child in children_of(node) {
