282	pub fn find_child_by_field<'a>(
283	    node: tree_sitter::Node<'a>,
284	    field: &str,
285	) -> Option<tree_sitter::Node<'a>> {
286	    let mut cursor = node.walk();
287	    for child in node.children(&mut cursor) {
288	        if child.kind() == field {
289	            return Some(child);
290	        }
291	    }
292	    node.child_by_field_name(field)
293	}
