295	pub fn make_function_info(
296	    node: tree_sitter::Node,
297	    source: &str,
298	    file: &str,
299	    config: &LangConfig,
300	) -> FunctionInfo {
301	    let start_line = node.start_position().row + 1;
302	    let end_line = node.end_position().row + 1;
303	    let hashes = collect_subtree_hashes(node, source, config);
304	    FunctionInfo {
305	        file: file.to_string(),
306	        start_line,
307	        end_line,
308	        node_hashes: hashes,
309	    }
310	}
