312	fn normalize_node_text(node: tree_sitter::Node, source: &str, config: &LangConfig) -> String {
313	    let kind = node.kind();
314	    if config.identifier_kinds.contains(&kind) {
315	        return "_ID".to_string();
316	    }
317	    if config.literal_kinds.contains(&kind) {
318	        return "_LIT".to_string();
319	    }
320	    let start = node.start_byte();
321	    let end = node.end_byte();
322	    source[start..end].to_string()
323	}
324	
325	pub fn build_normalized_subtree(
326	    node: tree_sitter::Node,
327	    source: &str,
328	    config: &LangConfig,
329	) -> String {
330	    if node.child_count() == 0 {
331	        return normalize_node_text(node, source, config);
332	    }
333	    let mut parts = vec![format!("({}:", node.kind())];
334	    let mut cursor = node.walk();
335	    for child in node.children(&mut cursor) {
336	        parts.push(build_normalized_subtree(child, source, config));
337	    }
338	    parts.push(")".to_string());
339	    parts.join("")
340	}
