342	fn hash_str(s: &str) -> u64 {
343	    use std::hash::{Hash, Hasher};
344	    let mut h = std::collections::hash_map::DefaultHasher::new();
345	    s.hash(&mut h);
346	    h.finish()
347	}
348	
349	fn collect_subtree_hashes(node: tree_sitter::Node, source: &str, config: &LangConfig) -> Vec<u64> {
350	    let mut hashes = Vec::new();
351	    collect_hashes_recursive(node, source, config, &mut hashes);
352	    hashes.sort_unstable();
353	    hashes
354	}
355	
356	fn collect_hashes_recursive(
357	    node: tree_sitter::Node,
358	    source: &str,
359	    config: &LangConfig,
360	    hashes: &mut Vec<u64>,
361	) {
362	    let subtree = build_normalized_subtree(node, source, config);
363	    hashes.push(hash_str(&subtree));
364	    let mut cursor = node.walk();
365	    for child in node.children(&mut cursor) {
366	        collect_hashes_recursive(child, source, config, hashes);
367	    }
368	}
