28	fn git_check_ignore(path: &Path) -> Option<bool> {
29	    let abs = path.canonicalize().ok()?;
30	    let parent = abs.parent()?;
31	    let output = Command::new("git")
32	        .args([
33	            "-C",
34	            &parent.to_string_lossy(),
35	            "check-ignore",
36	            "--",
37	            &abs.to_string_lossy(),
38	        ])
