81	/// Returns whether a file should be scanned.
82	/// When force_lang is Some, every non-excluded, non-builtin-excluded file is scanned.
83	/// When force_lang is None, only files with recognized extensions are scanned.
84	pub fn should_scan_file(
85	    path: &Path,
86	    exclude_set: &GlobSet,
87	    git_ignored: &dyn Fn(&Path) -> bool,
88	    force_lang: Option<Lang>,
89	) -> bool {
90	    if is_builtin_excluded(path) || should_skip(path, exclude_set) || git_ignored(path) {
91	        return false;
92	    }
93	    match force_lang {
94	        Some(_) => true,
95	        None => is_supported_file(path),
