101	    exclude_set: &GlobSet,
102	    force_lang: Option<Lang>,
103	) -> (Vec<FunctionInfo>, Vec<String>) {
104	    let mut functions: Vec<FunctionInfo> = Vec::new();
105	    let mut errors: Vec<String> = Vec::new();
106	    for path_str in paths {
