131	pub fn collect_from_single_file(
132	    path: &Path,
133	    exclude_set: &GlobSet,
134	    force_lang: Option<Lang>,
135	    functions: &mut Vec<FunctionInfo>,
136	    errors: &mut Vec<String>,
137	) {
138	    if should_scan_file(path, exclude_set, &is_git_ignored, force_lang) {
139	        let lang = force_lang.or_else(|| detect_lang(path)).unwrap();
140	        process_file(path, lang, functions, errors);
141	    }
