144	fn process_entry(
145	    entry: Result<walkdir::DirEntry, walkdir::Error>,
146	    exclude_set: &GlobSet,
147	    force_lang: Option<Lang>,
148	    functions: &mut Vec<FunctionInfo>,
149	    errors: &mut Vec<String>,
150	) {
151	    match entry {
152	        Ok(e)
153	            if e.file_type().is_file()
154	                && should_scan_file(e.path(), exclude_set, &is_git_ignored, force_lang) =>
155	        {
156	            let lang = force_lang.or_else(|| detect_lang(e.path())).unwrap();
157	            process_file(e.path(), lang, functions, errors);
158	        }
159	        Ok(_) => {}
160	        Err(err) => errors.push(format!("walk error: {}", err)),
161	    }
162	}
