164	pub fn collect_from_directory(
165	    path: &Path,
166	    exclude_set: &GlobSet,
167	    force_lang: Option<Lang>,
168	    functions: &mut Vec<FunctionInfo>,
169	    errors: &mut Vec<String>,
170	) {
171	    let walker = WalkDir::new(path)
172	        .sort_by_file_name()
173	        .into_iter()
174	        .filter_entry(|e| !e.file_type().is_dir() || !is_builtin_excluded(e.path()));
175	    for entry in walker {
176	        process_entry(entry, exclude_set, force_lang, functions, errors);
177	    }
